// Legacy slug aliases — pre-existing cards (home/products/calendar) use older
// slugs; map them to the catalogue product so detail pages show real data.
export const DETAIL_ALIASES = {"avocado": "avocado-hass", "mangoes": "mango", "snack-cucumber": "mini-snack-cucumber", "tomato-cherry-red": "tomato-cherry", "tomato-plum": "tomato-plum-roma", "zucchini-green": "zucchini", "potato-local": "potato", "marrow": "marrow-koosa", "beans": "beans-green"};
for (const [from, to] of Object.entries(DETAIL_ALIASES)) {
  if (DETAIL[to] && !DETAIL[from]) DETAIL[from] = DETAIL[to];
}
